diff --git a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
index a4831ea7c11f..6257e1500151 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -2889,6 +2889,15 @@ void VPPredInstPHIRecipe::execute(VPTransformState &State) {
       cast<Instruction>(State.get(getOperand(0), *State.Lane));
   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
   BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
+  // Handle the case where the predicated instruction is in a block with no
+  // predecessors (e.g., function entry block). In this case, we need to find
+  // the appropriate predicating block by looking at the VPlan structure.
+  if (!PredicatingBB) {
+    // The instruction is in the entry block, so the predicating block should
+    // be the vector preheader (PrevBB) which is the block that branches to
+    // the vector loop.
+    PredicatingBB = State.CFG.PrevBB;
+  }
   assert(PredicatingBB && "Predicated block has no single predecessor.");
   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
          "operand must be VPReplicateRecipe");
